import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import bookImage from "../assets/book-icon.svg"; // предполагаем, что ты сохранил иконку как SVG

function Home() {
  const user = useSelector((state) => state.auth.user);

  return (
    <div className="flex min-h-screen items-center justify-between px-16 bg-white">
      {/* Левая часть */}
      <div className="max-w-md">
        <h1 className="text-6xl font-light">
          School <span className="font-bold text-blue-600">App</span>
        </h1>
        <p className="mt-6 text-gray-700">
          Добро пожаловать в <strong>School App</strong> <br />
          {user ? (
            <>Здравствуйте, {user.name}! Вы вошли как {user.role}.</>
          ) : (
            <>Пожалуйста, войдите или зарегистрируйтесь.</>
          )}
        </p>

        {!user && (
          <div className="mt-6 flex gap-4">
            <Link
              to="/login"
              className="bg-blue-600 text-white px-6 py-2 rounded-full hover:bg-blue-700 transition"
            >
              login
            </Link>
            <Link
              to="/register"
              className="bg-blue-600 text-white px-6 py-2 rounded-full hover:bg-blue-700 transition"
            >
              register
            </Link>
          </div>
        )}
      </div>

      {/* Правая часть с иконкой */}
      <div className="w-1/2 flex justify-center">
        <img src={bookImage} alt="Book on phone" className="w-96" />
      </div>
    </div>
  );
}

export default Home;
